# Type everything as STRING first: numeric amounts and epoch event-times can
# arrive quoted; typing them natively would turn bad values into silent nulls.
SCHEMA = "order_id string, amount string, event_time string"


def _amount_double():
    # numbers OR numeric text both cast cleanly; garbage -> null (quarantined)
    return F.col("amount").cast("double")


def _epoch_seconds():
    # event_time arrives as epoch-millis digits OR an ISO-8601 string.
    is_epoch = F.col("event_time").rlike("^[0-9]+$")
    return F.when(
        is_epoch,
        F.col("event_time").cast("long") / F.lit(1000.0),
    ).otherwise(
        # to_timestamp parses ISO-8601 (incl. offset/Z) -> true instant;
        # unix_timestamp yields tz-independent epoch seconds.
        F.unix_timestamp(F.to_timestamp(F.col("event_time"))).cast("double")
    )


def _utc_event_date(epoch_sec_col):
    # UTC calendar day via day-arithmetic: days since epoch, NO session tz used.
    days = F.floor(epoch_sec_col / F.lit(86400.0)).cast("int")
    return F.date_add(F.lit("1970-01-01").cast("date"), days)


# ---- RAW: land every line, parse leniently, keep original text -------------
@dp.materialized_view(name="orders_raw")
def orders_raw():
    raw = SparkSession.active().read.text(INPUT)
    return raw.withColumn("j", F.from_json(F.col("value"), SCHEMA)).select(
        F.col("value"),
        F.col("j.order_id").alias("order_id"),
        F.col("j.amount").alias("amount"),
        F.col("j.event_time").alias("event_time"),
    )


