@dp.materialized_view(name="orders_quarantine")
def orders_quarantine():
    df = SparkSession.active().read.table("orders_raw")
    epoch_sec = _epoch_seconds()
    amount_d = _amount_double()
    event_date = _utc_event_date(epoch_sec)
    bad = (
        F.col("order_id").isNull()
        | amount_d.isNull()
        | event_date.isNull()
    )
    return df.where(bad).select("value")


# ---- VALIDATED: only rows passing every expectation ------------------------
@dp.materialized_view(name="orders_validated")
def orders_validated():
    df = SparkSession.active().read.table("orders_raw")
    epoch_sec = _epoch_seconds()
    out = (
        df.withColumn("amount_d", _amount_double())
        .withColumn("event_date", _utc_event_date(epoch_sec))
    )
    return out.where(
        F.col("order_id").isNotNull()
        & F.col("amount_d").isNotNull()
        & F.col("event_date").isNotNull()
    ).select("order_id", "amount_d", "event_date")


# ---- GOLD: daily UTC revenue total over every real order -------------------
@dp.materialized_view(name="gold_daily")
def gold_daily():
    df = SparkSession.active().read.table("orders_validated")
    return df.groupBy("event_date").agg(
        F.sum("amount_d").alias("revenue")
    )

