@dp.materialized_view(name="orders_validated")
def orders_validated():
    df = SparkSession.active().read.table("orders_raw")
    return df.selectExpr(
        # amounts: strip currency/text noise, then try_cast (no ANSI exception)
        "try_cast(regexp_replace(cast(amount as string), '[^0-9.+-]', '') as double) as amount",
        # event_date: parse multiple time formats, fall back to epoch seconds,
        # then convert the instant to its UTC calendar day via epoch-day math
        # (floor(epoch/86400) is UTC and independent of session timezone).
        """
        date_from_unix_date(
          cast(
            floor(
              unix_timestamp(
                coalesce(
                  try_to_timestamp(cast(event_time as string)),
                  try_to_timestamp(cast(event_time as string), 'yyyy-MM-dd HH:mm:ss'),
                  try_to_timestamp(cast(event_time as string), 'yyyy-MM-dd''T''HH:mm:ss'),
                  try_to_timestamp(cast(event_time as string), 'MM/dd/yyyy HH:mm:ss'),
                  try_to_timestamp(cast(event_time as string), 'yyyy/MM/dd HH:mm:ss'),
                  case when cast(event_time as string) rlike '^[0-9]+$'
                       then timestamp_seconds(cast(event_time as bigint)) end
                )
              ) / 86400
            ) as int
          )
        ) as event_date
        """,
    ).where("amount is not null and event_date is not null")


