# Candidate names used defensively via coalesce of existing columns.
_OP_DELETE = ["delete", "remove", "removal", "d", "del", "tombstone"]


@dp.materialized_view(name="customers_cdc_raw")
def customers_cdc_raw():
    # spark.read.json is explicitly allowed (lazy plan); no action forced here.
    return SparkSession.active().read.json(DATA)


@dp.materialized_view(name="customers_history")
def customers_history():
    df = SparkSession.active().read.table("customers_cdc_raw")

    # Normalize the intrinsic ordering key (jumbled file order is irrelevant).
    seq = F.col("seq").cast("long")
    op = F.lower(F.trim(F.col("op").cast("string")))

    norm = (
        df.select(
            F.col("customer_id"),
            seq.alias("seq"),
            op.alias("op"),
            F.col("tier").cast("string").alias("tier"),
            F.col("region").cast("string").alias("region"),
        )
        # Idempotency: a replayed/reloaded event is identical on its version key.
        .dropDuplicates(["customer_id", "seq"])
    )

    w = Window.partitionBy("customer_id").orderBy(F.col("seq").asc())
    return norm.withColumn("version", F.row_number().over(w)).select(
        "customer_id", "version", "seq", "op", "tier", "region"
    )


