def customers_current():
    h = SparkSession.active().read.table("customers_history")

    w = Window.partitionBy("customer_id").orderBy(F.col("seq").desc())
    latest = h.withColumn("_rn", F.row_number().over(w)).where(F.col("_rn") == 1)

    # Most recent REAL state: if the newest event is a removal, the customer is gone.
    return (
        latest.where(~F.col("op").isin(_OP_DELETE))
        .select("customer_id", "tier", "region")
    )

