def _first(line, *keys):
    return F.coalesce(*[F.get_json_object(line, "$." + k) for k in keys])


@dp.materialized_view(name="orders_clean")
def orders_clean():
    spark = SparkSession.active()
    # read as TEXT -> fixed schema (value:string), no schema inference action.
    raw = spark.read.text(DATA).select(F.col("value").alias("line"))
    raw = raw.where(F.length(F.trim(F.col("line"))) > 0)

    merchant = _first("line", "merchant", "merchant_id", "merchantId", "seller", "store")
    category = _first("line", "category", "cat", "category_name", "categoryId")
    revenue_raw = _first("line", "revenue", "amount", "total", "price", "value", "sales")

    # strip currency symbols / commas / spaces, then cast; keep the row even if null.
    revenue = F.regexp_replace(revenue_raw, "[^0-9.\\-]", "").cast("double")

    return raw.select(
        # never drop a row: unknown merchant/category become explicit buckets.
        F.coalesce(merchant, F.lit("__unknown__")).alias("merchant"),
        F.coalesce(category, F.lit("__uncategorized__")).alias("category"),
        F.coalesce(revenue, F.lit(0.0)).alias("revenue"),
    )


@dp.materialized_view(name="merchant_totals")
def merchant_totals():
    df = SparkSession.active().read.table("orders_clean")
    return df.groupBy("merchant").agg(F.sum("revenue").alias("revenue"))


