@dp.materialized_view(name="customers_current")
def customers_current():
    df = SparkSession.active().read.table("customers_cdc_raw")

    # Normalize the change-operation so 'D'/'delete'/'DELETE' all compare equal.
    op_norm = F.lower(F.trim(F.col("op").cast("string")))

    # Deterministic "latest event per customer":
    #   primary  = sequence/version descending (newest state wins)
    #   tiebreak = op then tier then region, so identical seqs resolve stably
    #              and reprocessing the same input yields the same result.
    w = Window.partitionBy("customer_id").orderBy(
        F.col("seq").cast("long").desc_nulls_last(),
        op_norm.desc_nulls_last(),
        F.col("tier").cast("string").desc_nulls_last(),
        F.col("region").cast("string").desc_nulls_last(),
    )

    ranked = (
        df.withColumn("_op", op_norm)
          .withColumn("_rn", F.row_number().over(w))
    )

    latest = ranked.where(F.col("_rn") == 1)

    # Exclude customers whose current (latest) state is a removal.
    current = latest.where(
        ~F.col("_op").isin("d", "delete", "deleted", "remove", "removed")
    )

    return current.select("customer_id", "tier", "region")


