def _cols(path):
    # schema inference at MODULE level (never inside a query function)
    try:
        return set(SparkSession.active().read.json(path).columns)
    except Exception:
        return set()


def _pick(cols, candidates):
    for c in candidates:
        if c in cols:
            return c
    return candidates[0]


def _pick_opt(cols, candidates):
    for c in candidates:
        if c in cols:
            return c
    return None


_T = _cols(TRADES)
_F = _cols(FX)

T_ID = _pick(_T, ["trade_id", "tradeId", "id", "txn_id", "transaction_id", "trade"])
T_CCY = _pick(_T, ["currency", "ccy", "curr", "trade_currency", "ccy_code"])
T_AMT = _pick(_T, ["amount", "notional", "qty", "quantity", "value", "amt", "trade_amount"])
T_TS = _pick(_T, ["trade_ts", "trade_time", "traded_at", "timestamp", "ts", "event_time", "event_ts", "time", "trade_date"])

FX_CCY = _pick(_F, ["currency", "ccy", "curr", "ccy_code", "pair"])
FX_RATE = _pick(_F, ["rate", "fx_rate", "usd_rate", "rate_usd", "price", "value"])
FX_VF = _pick(_F, ["valid_from", "effective_from", "effective_ts", "as_of", "valid_from_ts",
                   "start_ts", "effective_time", "from_ts", "valid_start"])
FX_ORD = _pick_opt(_F, ["version", "seq", "sequence", "change_seq", "seq_num", "revision",
                        "updated_at", "ingested_at", "ingest_ts", "recorded_at", "cdc_ts",
                        "op_ts", "change_ts", "emit_ts", "source_ts", "_seq"])


@dp.materialized_view(name="fx_rates_dim")
def fx_rates_dim():
    spark = SparkSession.active()
    df = spark.read.json(FX)
    sel = [
        F.col(FX_CCY).alias("currency"),
        F.col(FX_RATE).cast("double").alias("rate"),
        F.to_timestamp(F.col(FX_VF)).alias("valid_from"),
    ]
    if FX_ORD:
        sel.append(F.col(FX_ORD).cast("string").alias("__ord"))
    df = df.select(*sel)
    if not FX_ORD:
        df = df.withColumn("__ord", F.lit("0"))

    # collapse CDC corrections: keep latest version per (currency, valid_from)
    wd = Window.partitionBy("currency", "valid_from").orderBy(
        F.col("__ord").desc(), F.col("rate").desc()
    )
    deduped = (
        df.withColumn("__rn", F.row_number().over(wd))
          .where(F.col("__rn") == 1)
          .drop("__rn", "__ord")
    )

    # non-overlapping validity intervals: [valid_from, next valid_from)
    wv = Window.partitionBy("currency").orderBy("valid_from")
    out = deduped.withColumn("valid_to", F.lead("valid_from").over(wv))
    return out.select("currency", "rate", "valid_from", "valid_to")


