@dp.materialized_view(name="gold_trades")
def gold_trades():
    spark = SparkSession.active()
    t = spark.read.json(TRADES).select(
        F.col(T_ID).cast("string").alias("trade_id"),
        F.col(T_CCY).alias("currency"),
        F.col(T_AMT).cast("double").alias("amount"),
        F.to_timestamp(F.col(T_TS)).alias("trade_ts"),
    )
    d = spark.read.table(f"{CAT}.fx_rates_dim").select(
        F.col("currency").alias("d_ccy"),
        F.col("rate").alias("d_rate"),
        F.col("valid_from").alias("d_from"),
        F.col("valid_to").alias("d_to"),
    )
    cond = (
        (t["currency"] == d["d_ccy"])
        & (t["trade_ts"] >= d["d_from"])
        & (d["d_to"].isNull() | (t["trade_ts"] < d["d_to"]))
