from pyspark.sql import SparkSession, Window, functions as F

INPUT = "file:///home/lnc/repos/safe-spark-agents/.worktrees/dev-sweep/experiments/safe_agent_study/.work_seed_s3/_data/gen_customers_cdc_seed1337.ndjson"

# Type everything as string first; validate/cast later (never let bad values become silent nulls in schema).
SCHEMA = (
    "customer_id string, tier string, region string, "
    "event_time string, updated_at string, ts string, timestamp string, "
    "seq string, sequence string, version string, op string, operation string"
)


def _event_ts(col):
    digits = F.col(col).rlike("^[0-9]+$")
    as_long = F.col(col).cast("long")
    return (
        F.when(digits & (F.length(F.col(col)) >= F.lit(13)), F.timestamp_millis(as_long))
        .when(digits, F.timestamp_seconds(as_long))
        # to_timestamp parses ISO-8601; offset/'Z' forms are interpreted to UTC instant
        .otherwise(F.to_timestamp(F.col(col)))
    )


@dp.materialized_view(name="customers_quarantine")
def customers_quarantine():
    raw = SparkSession.active().read.text(INPUT)
    parsed = raw.withColumn("j", F.from_json("value", SCHEMA))
    j = parsed.select("value", "j.*")
    ts_src = F.coalesce(F.col("event_time"), F.col("updated_at"), F.col("ts"), F.col("timestamp"))
    j = j.withColumn("_ts_src", ts_src)
    j = j.withColumn("event_ts", _event_ts("_ts_src"))
    bad = (
        F.col("customer_id").isNull()
        | (F.length(F.trim(F.col("customer_id"))) == 0)
        | F.col("_ts_src").isNull()
        | F.col("event_ts").isNull()
    )
    return j.where(bad).select("value")


@dp.materialized_view(name="customers_clean")
def customers_clean():
    raw = SparkSession.active().read.text(INPUT)
    parsed = raw.withColumn("j", F.from_json("value", SCHEMA)).select("j.*")

    ts_src = F.coalesce(
        F.col("event_time"), F.col("updated_at"), F.col("ts"), F.col("timestamp")
    )
    seq_src = F.coalesce(
        F.col("seq").cast("long"),
        F.col("sequence").cast("long"),
        F.col("version").cast("long"),
        F.lit(0).cast("long"),
    )

    df = (
        parsed.withColumn("_ts_src", ts_src)
        .withColumn("event_ts", _event_ts("_ts_src"))
        .withColumn("seq", seq_src)
    )

    # expectations: keep only rows with a real key and a parseable event time
    df = df.where(
        F.col("customer_id").isNotNull()
        & (F.length(F.trim(F.col("customer_id"))) > 0)
        & F.col("event_ts").isNotNull()
    )

    # deterministic dedup: one survivor per (customer_id, event_ts), highest sequence wins
    w = Window.partitionBy("customer_id", "event_ts").orderBy(
        F.col("seq").desc_nulls_last()
    )
    df = df.withColumn("_rn", F.row_number().over(w)).where(F.col("_rn") == 1).drop("_rn")

    return df.select("customer_id", "tier", "region", "event_ts", "seq")


@dp.materialized_view(name="customers_history")
def customers_history():
    df = SparkSession.active().read.table("customers_clean")

    # order each customer's changes deterministically by event time then sequence
    w = Window.partitionBy("customer_id").orderBy(
        F.col("event_ts").asc(), F.col("seq").asc()
    )

    nxt = F.lead("event_ts").over(w)
    out = (
        df.withColumn("valid_from", F.col("event_ts"))
        .withColumn("valid_to", nxt)  # half-open [valid_from, valid_to); null = open-ended current
        .withColumn("is_current", nxt.isNull())
    )

    return out.select(
        "customer_id", "tier", "region", "valid_from", "valid_to", "is_current"
    )


@dp.materialized_view(name="customers_current")
def customers_current():
    h = SparkSession.active().read.table("customers_history")
    return h.where(F.col("is_current")).select("customer_id", "tier", "region")

