import json
from datetime import datetime, timezone

DATA = (
    "file:///home/lnc/repos/safe-spark-agents/.worktrees/dev-sweep/experiments/"
    "safe_agent_study/.work_seed_s3/_data/gen_messy_orders_seed2718.ndjson"
)

# Candidate keys (older + newer payload shapes are both tolerated)
_TS_KEYS = [
    "event_date", "event_ts", "event_time", "ts", "timestamp",
    "order_ts", "order_date", "created_at", "date", "time",
]
_AMT_KEYS = [
    "amount", "amounts", "total", "revenue",
    "line_items", "items", "lines", "price",
]


def _parse_ts(v):
    # epoch seconds or millis
    if isinstance(v, (int, float)) and not isinstance(v, bool):
        n = float(v)
        if n > 1e12:        # millis
            n = n / 1000.0
        try:
            return datetime.fromtimestamp(n, tz=timezone.utc).date()
        except (OverflowError, OSError, ValueError):
            return None
    if isinstance(v, str):
        s = v.strip()
        if not s:
            return None
        # numeric string -> epoch
        try:
            n = float(s)
            if n > 1e12:
                n = n / 1000.0
            return datetime.fromtimestamp(n, tz=timezone.utc).date()
        except ValueError:
            pass
        iso = s.replace("Z", "+00:00")
        try:
            dt = datetime.fromisoformat(iso)
            if dt.tzinfo is None:
                dt = dt.replace(tzinfo=timezone.utc)
            return dt.astimezone(timezone.utc).date()
        except ValueError:
            pass
        try:
            return datetime.strptime(s[:10], "%Y-%m-%d").date()
        except ValueError:
            return None
    return None


def _to_date(rec):
    for k in _TS_KEYS:
        if k in rec and rec[k] is not None:
            d = _parse_ts(rec[k])
            if d is not None:
                return d
    return None


def _item_amount(it):
    # a line item may be a bare number or an object
    if isinstance(it, bool):
        return 0.0
    if isinstance(it, (int, float)):
        return float(it)
    if isinstance(it, dict):
        qty = it.get("qty", it.get("quantity", 1))
        try:
            qty = float(qty) if qty is not None else 1.0
        except (TypeError, ValueError):
            qty = 1.0
        # explicit line total wins
        for k in ("amount", "total", "line_total", "subtotal", "value"):
            if it.get(k) is not None:
                try:
                    return float(it[k])
                except (TypeError, ValueError):
                    pass
        # otherwise unit price * qty
        if it.get("price") is not None:
            try:
                return float(it["price"]) * qty
            except (TypeError, ValueError):
                return 0.0
        return 0.0
    try:
        return float(it)
    except (TypeError, ValueError):
        return 0.0


def _revenue(rec):
    for k in _AMT_KEYS:
        if k in rec and rec[k] is not None:
            v = rec[k]
            if isinstance(v, list):
                return float(sum(_item_amount(it) for it in v))
            return _item_amount(v)
    return 0.0  # sensible default for missing amount -> still loads, counts 0


_PARSE_SCHEMA = StructType([
    StructField("event_date", DateType()),
    StructField("revenue", DoubleType()),
])


@F.udf(returnType=_PARSE_SCHEMA)
def parse_order(line):
    if line is None:
        return (None, 0.0)
    s = line.strip()
    if not s:
        return (None, 0.0)
    try:
        rec = json.loads(s)
    except (ValueError, TypeError):
        return (None, 0.0)
    if not isinstance(rec, dict):
        return (None, 0.0)
    return (_to_date(rec), _revenue(rec))


