@dp.materialized_view(name="parsed")
def parsed():
    df = SparkSession.active().read.table("bronze")
    v = F.col("value")

    order_id = F.get_json_object(v, "$.order_id")
    amount_raw = F.coalesce(
        F.get_json_object(v, "$.amount"),
        F.get_json_object(v, "$.revenue"),
        F.get_json_object(v, "$.price"),
    )
    category = F.coalesce(
        F.get_json_object(v, "$.category"),
        F.get_json_object(v, "$.cat"),
    )
    ts_raw = F.coalesce(
        F.get_json_object(v, "$.ts"),
        F.get_json_object(v, "$.event_time"),
        F.get_json_object(v, "$.timestamp"),
        F.get_json_object(v, "$.order_ts"),
        F.get_json_object(v, "$.created_at"),
        F.get_json_object(v, "$.event_date"),
    )

    # Null-safe numeric parse: strip currency noise, then try_cast (never throws).
    amount_str = F.regexp_replace(amount_raw, r"[^0-9.eE+\-]", "")
    df = df.select(
        v.alias("value"),
        F.trim(order_id).alias("order_id"),
        amount_str.alias("amount_str"),
        category.alias("category"),
        ts_raw.alias("ts_raw"),
    )

    df = df.withColumn("amount", F.expr("try_cast(amount_str as double)"))

    # Null-safe timestamp parse: ISO strings, epoch seconds, epoch millis.
    df = df.withColumn(
        "event_ts",
        F.coalesce(
            F.expr("try_to_timestamp(ts_raw)"),
            F.expr(
                "CASE WHEN ts_raw rlike '^[0-9]{10}$' THEN timestamp_seconds(cast(ts_raw as long)) END"
            ),
            F.expr(
                "CASE WHEN ts_raw rlike '^[0-9]{13}$' THEN timestamp_millis(cast(ts_raw as long)) END"
            ),
        ),
    )
    # UTC calendar day
    df = df.withColumn("event_date", F.to_date(df["event_ts"]))

    base_reason = (
        F.when(F.col("order_id").isNull() | (F.col("order_id") == ""), F.lit("missing_order_id"))
        .when(F.col("amount").isNull(), F.lit("invalid_amount"))
        .when(F.col("event_date").isNull(), F.lit("invalid_date"))
        .otherwise(F.lit(None))
    )
    df = df.withColumn("base_reason", base_reason)
    df = df.withColumn("is_valid", F.col("base_reason").isNull())
    return df


@dp.materialized_view(name="flagged")
def flagged():
    df = SparkSession.active().read.table("parsed")
    # Deterministic dedup: first valid row per order_id is kept; later valid
    # duplicates are quarantined so clean_orders is truly keyed by order_id.
    w = Window.partitionBy("order_id").orderBy(
        F.col("is_valid").desc(),
        F.col("event_ts").asc_nulls_last(),
        F.col("value").asc(),
    )
    df = df.withColumn("rn", F.row_number().over(w))
    reason = (
        F.when(F.col("base_reason").isNotNull(), F.col("base_reason"))
        .when(F.col("rn") > 1, F.lit("duplicate_order_id"))
        .otherwise(F.lit(None))
    )
    return df.withColumn("reason", reason)


@dp.materialized_view(name="clean_full")
def clean_full():
    df = SparkSession.active().read.table("flagged")
    return df.where(F.col("reason").isNull()).select(
        F.col("order_id"),
        F.col("amount").cast("double").alias("amount"),
        F.col("category"),
        F.col("event_date").cast("date").alias("event_date"),
    )


@dp.materialized_view(name="clean_orders")
def clean_orders():
    df = SparkSession.active().read.table("clean_full")
    # Keyed by order_id, carrying amount, category.
    return df.select("order_id", "amount", "category")


@dp.materialized_view(name="gold_daily")
def gold_daily():
    df = SparkSession.active().read.table("clean_full")
    return df.select(
        F.col("event_date"),
        F.col("amount").alias("revenue"),
        F.col("order_id"),
        F.col("amount"),
        F.col("category"),
    )


@dp.materialized_view(name="rejected_orders")
def rejected_orders():
    df = SparkSession.active().read.table("flagged")
    return df.where(F.col("reason").isNotNull()).select(
        F.col("order_id"),
        F.col("value").alias("raw_record"),
        F.col("amount_str").alias("amount_raw"),
        F.col("ts_raw"),
        F.col("reason"),
    )


@dp.materialized_view(name="recon_orders")
def recon_orders():
    df = SparkSession.active().read.table("flagged")
    agg = df.agg(
        F.count(F.lit(1)).alias("source_count"),
