def _spark():
    s = SparkSession.getActiveSession()
    return s if s is not None else SparkSession.builder.getOrCreate()


# --- Resolve the messy upstream schema ONCE, at load time (not in a query fn) ---
try:
    _COLS = set(_spark().read.json(DATA).columns)
except Exception:
    _COLS = set()


def pick(*cands):
    for c in cands:
        if c in _COLS:
            return c
    return None


TS   = pick("event_time", "event_ts", "timestamp", "ts", "created_at",
            "occurred_at", "settlement_ts", "payment_time", "time", "datetime")
DT   = pick("settlement_date", "date", "day", "business_date", "value_date")
CCY  = pick("currency", "ccy", "currency_code", "curr", "cur")
AMT  = pick("amount", "value", "amount_value", "settled_amount",
            "gross_amount", "amount_original")
RATE = pick("fx_rate", "rate", "exchange_rate", "usd_rate", "rate_to_usd", "fx")
USD  = pick("usd_amount", "amount_usd", "usd_value", "settled_usd", "value_usd", "usd")
SRC  = pick("record_type", "type", "kind", "source", "feed", "origin", "system", "channel")

_EXTERNAL = ["bank", "external", "external_feed", "settlement_feed", "settlements",
             "bank_settlement", "bank_feed", "feed"]


def _utc_day():
    """UTC calendar day, timezone-independent & deterministic (no session conf mutation)."""
    if TS is not None:
        epoch = F.col(TS).cast("timestamp").cast("long")
        return F.date_add(F.to_date(F.lit("1970-01-01")),
                          (epoch / F.lit(86400)).cast("int"))
    if DT is not None:
        return F.to_date(F.col(DT))
    return F.lit(None).cast("date")


def _usd():
    if USD is not None:
        return F.col(USD).cast("double")
    if AMT is not None and RATE is not None:
        return F.col(AMT).cast("double") * F.col(RATE).cast("double")
    if AMT is not None:
        return F.col(AMT).cast("double")
    return F.lit(0.0)


def _currency():
    return F.upper(F.col(CCY).cast("string")) if CCY else F.lit("USD")


def _amount():
    return F.col(AMT).cast("double") if AMT else F.lit(None).cast("double")


def _is_external():
    if SRC is None:
        return F.lit(False)
    return F.lower(F.col(SRC).cast("string")).isin(_EXTERNAL)


@dp.materialized_view(name="settlement_norm")
def settlement_norm():
    df = _spark().read.json(DATA)
    return (df.select(
                _utc_day().alias("settlement_date"),
                _currency().alias("currency"),
                _usd().alias("usd_value"),
                _amount().alias("ccy_amount"),
                _is_external().alias("is_external"),
            )
            .where(F.col("settlement_date").isNotNull()))


@dp.materialized_view(name="settlement_daily")
def settlement_daily():
    n = _spark().read.table(f"{CAT}.settlement_norm").where(~F.col("is_external"))
    return (n.groupBy("settlement_date")
             .agg(F.round(F.sum("usd_value"), 2).alias("usd_total"))
             .orderBy("settlement_date"))


@dp.materialized_view(name="settlement_by_currency")
def settlement_by_currency():
    n = _spark().read.table(f"{CAT}.settlement_norm").where(~F.col("is_external"))
    return (n.groupBy("settlement_date", "currency")
             .agg(F.round(F.sum("usd_value"), 2).alias("usd_total"),
                  F.round(F.sum("ccy_amount"), 2).alias("currency_total"))
             .orderBy("settlement_date", "currency"))


@dp.materialized_view(name="settlement_reconciliation")
def settlement_reconciliation():
    n = _spark().read.table(f"{CAT}.settlement_norm")
    internal = (n.where(~F.col("is_external"))
                 .groupBy("settlement_date", "currency")
                 .agg(F.round(F.sum("usd_value"), 2).alias("internal_usd")))
    external = (n.where(F.col("is_external"))
                 .groupBy("settlement_date", "currency")
                 .agg(F.round(F.sum("usd_value"), 2).alias("external_usd")))
    j = internal.join(external, ["settlement_date", "currency"], "full_outer")
    diff = (F.coalesce(F.col("internal_usd"), F.lit(0.0))
            - F.coalesce(F.col("external_usd"), F.lit(0.0)))
    return (j.select(
                "settlement_date",
                "currency",
                F.coalesce(F.col("internal_usd"), F.lit(0.0)).alias("internal_usd"),
                F.coalesce(F.col("external_usd"), F.lit(0.0)).alias("external_usd"),
                F.round(diff, 2).alias("diff_usd"),
                (F.abs(diff) < F.lit(0.005)).alias("reconciled"),
            )
            .orderBy("settlement_date", "currency"))

